import com.amazonaws.auth.{AWSCredentials, BasicAWSCredentials}
import com.amazonaws.services.s3.AmazonS3ClientBuilder

class MyService {
  private val credentials = new BasicAWSCredentials("YOUR_ACCESS_KEY", "YOUR_SECRET_KEY")

  def getObject(bucket: String, key: String): Unit = {
    val s3Client = AmazonS3ClientBuilder.standard()
      .withCredentials(credentials)
      .build()

    // Use the S3 client to perform operations on the bucket and key
    val objectMetadata = s3Client.getObjectMetadata(bucket, key)
    println(s"Object metadata: $objectMetadata")
  }
}